+// isMayorShellCommand checks if the command is a shell (meaning Claude has exited).
+func isMayorShellCommand(cmd string) bool {
+	shells := []string{"bash", "zsh", "sh", "fish", "tcsh", "ksh"}
+	for _, shell := range shells {
+		if cmd == shell {
+			return true
+		}
+	}
+	return false
+}
